import numpy as np

def algo(initial_population, individual_upper, individual_lower, objective_function):
    population = initial_population
    best_solution = None
    best_fitness = float('inf')
    evaluations = 0
    max_evaluations = 30000
    num_layers = 5
    layers = np.array_split(population, num_layers)
    memory = []

    while evaluations < max_evaluations:
        for layer in range(num_layers):
            fitness_values = np.apply_along_axis(objective_function, 1, layers[layer])
            evaluations += len(fitness_values)
            min_index = np.argmin(fitness_values)
            if fitness_values[min_index] < best_fitness:
                best_fitness = fitness_values[min_index]
                best_solution = layers[layer][min_index]

            adaptive_step = 0.1 + (0.5 - (0.5 * (best_fitness - fitness_values) / (best_fitness + 1e-8)))
            adaptive_step = np.clip(adaptive_step, 0.1, 0.5)
            new_population = np.zeros_like(layers[layer])
            for i in range(len(layers[layer])):
                grad = np.gradient(fitness_values)
                perturb_factor = 0.1 * (1 - (evaluations / max_evaluations))
                perturbation = np.random.uniform(-perturb_factor, perturb_factor, layers[layer][i].shape)
                new_solution = layers[layer][i] - adaptive_step[i] * grad[i] + perturbation
                new_population[i] = np.clip(new_solution, individual_lower, individual_upper)
            layers[layer] = new_population

            if layer < num_layers - 1:
                better_individuals = layers[layer][fitness_values < np.mean(fitness_values)]
                if len(better_individuals) > 0:
                    layers[layer + 1] = 0.5 * layers[layer + 1] + 0.5 * np.mean(better_individuals, axis=0)

            if len(memory) < 20:
                for ind in layers[layer]:
                    if ind.tolist() not in memory:
                        memory.append(ind.tolist())
            else:
                for ind in layers[layer]:
                    if ind.tolist() not in memory:
                        idx = np.random.randint(len(memory))
                        memory[idx] = ind.tolist()

    return best_solution
